"""Practical sampling profiles for an agentic pipeline using the Anthropic SDK."""

import anthropic

client = anthropic.Anthropic()   # reads ANTHROPIC_API_KEY from env

TOOL_CALL_PROFILE = {
    "temperature": 0.0,  # deterministic tool routing
    "top_p": 1.0,        # no nucleus truncation needed at T=0
}

STRUCTURED_OUTPUT_PROFILE = {
    "temperature": 0.3,
    "top_p": 0.95,
}

CREATIVE_DRAFT_PROFILE = {
    "temperature": 0.9,
    "top_p": 0.9,
}

SELF_CONSISTENCY_PROFILE = {
    "temperature": 0.7,
    "top_p": 0.95,
}


def call_model(prompt: str, profile: dict, system: str = "") -> str:
    """Make a single API call using the given sampling profile."""
    kwargs = {
        "model": "claude-opus-4-5",
        "max_tokens": 512,
        "messages": [{"role": "user", "content": prompt}],
        **profile,
    }
    if system:
        kwargs["system"] = system
    response = client.messages.create(**kwargs)
    return response.content[0].text


def self_consistency_vote(prompt: str, n: int = 5) -> str:
    """Sample N independent completions and pick the majority answer."""
    answers = [call_model(prompt, SELF_CONSISTENCY_PROFILE) for _ in range(n)]
    from collections import Counter
    return Counter(answers).most_common(1)[0][0]


if __name__ == "__main__":
    # Tool-call step: deterministic
    tool_resp = call_model(
        "Which tool should I call to get today's weather? Reply with only the tool name.",
        TOOL_CALL_PROFILE,
        system="Available tools: get_weather, get_calendar, send_email",
    )
    print("Tool selection:", tool_resp)

    # Creative step: higher temperature
    draft = call_model(
        "Write a one-sentence tagline for a dog-walking app.",
        CREATIVE_DRAFT_PROFILE,
    )
    print("Draft tagline:", draft)
